// MidPoint 4.10: NO usar focus.extension.<item> (ExtensionType no expone items
// como propiedades Groovy → MissingPropertyException). API canónica:
// basic.getExtensionPropertyValue(object, localName).
def ls = focus?.lifecycleState
def worker  = basic.getExtensionPropertyValue(focus, 'liveAffiliationWorker')
def student = basic.getExtensionPropertyValue(focus, 'liveAffiliationStudent')
def live = (worker != null) || (student != null)
return (ls == 'active' || ls == null) && live
